2044 |     /**
2045 |      * Tries to parse JSON. If it fails due to bad escaping (common with AI),
2046 |      * it attempts to double-escape backslashes that aren't valid JSON control chars.
2047 |      */
2048 |     function smartJSONParse(jsonString) {
2049 |         try {
2050 |             return JSON.parse(jsonString);
2051 |         } catch (e) {
2052 |             console.warn("Standard JSON parse failed, attempting Robust Auto-Fix...");
2053 |             let fixed = jsonString
2054 |                 // 1. Fix backslashes that aren't part of a valid escape sequence
2055 |                 .replace(/\\(?!["\\/bfnrtu])/g, "\\\\")
2056 |                 // 2. Fix literal newlines inside strings (replace with \n)
2057 |                 .replace(/(\n)/g, (match, p1, offset) => {
2058 |                     // Only replace if we are likely inside a quoted string
2059 |                     const before = jsonString.slice(0, offset);
2060 |                     const quoteCount = (before.match(/"/g) || []).length;
2061 |                     return (quoteCount % 2 === 1) ? "\\n" : "\n";
2062 |                 });
2063 | 
2064 |             try {
2065 |                 const cleanObj = JSON.parse(fixed);
2066 |                 document.getElementById('json-input').value = fixed;
2067 |                 if (typeof saveState === 'function') saveState();
2068 |                 showGlobalToast("✨ Robust Auto-Correction Applied");
2069 |                 return cleanObj;
2070 |             } catch (e2) {
2071 |                 console.error("Robust fix failed:", e2);
2072 |                 throw e; // Throw original error for better debugging
2073 |             }
2074 |         }
2075 |     }
