2308 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2309 |     function applyLocalPatch(content, ops) {
2310 |         let lines = content.split('\n');
2311 |         let logs = [];
2312 |         let success = true;
2313 | 
2314 |         if (typeof ops === 'string') {
2315 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2316 |         }
2317 | 
2318 |         ops.forEach(op => {
2319 |             if (op.action === 'comment') return;
2320 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2321 |             
2322 |             if (op.action === 'replace_block') {
2323 |                 // Strategy 1: Exact String Match (Fastest)
2324 |                 const currentStr = lines.join('\n');
2325 |                 if (currentStr.includes(op.find_block)) {
2326 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2327 |                     logs.push('Exact match applied');
2328 |                     return;
2329 |                 }
2330 | 
2331 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2332 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2333 |                 if (searchLines.length === 0) return;
2334 | 
2335 |                 let matchStart = -1;
2336 |                 let matchEnd = -1;
2337 | 
2338 |                 // Scan file lines
2339 |                 for (let i = 0; i < lines.length; i++) {
2340 |                     // If first line matches (ignoring whitespace)
2341 |                     if (lines[i].trim() === searchLines[0]) {
2342 |                         // Check subsequent lines
2343 |                         let allMatch = true;
2344 |                         let fileOffset = 0;
2345 |                         let searchOffset = 1;
2346 |                         
2347 |                         while (searchOffset < searchLines.length) {
2348 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2349 |                             const nextFile = lines[i + fileOffset + 1].trim();
2350 |                             // Skip empty lines in file if they aren't in search block
2351 |                             if (nextFile === '') {
2352 |                                 fileOffset++;
2353 |                                 continue;
2354 |                             }
2355 |                             if (nextFile !== searchLines[searchOffset]) {
2356 |                                 allMatch = false;
2357 |                                 break;
2358 |                             }
2359 |                             fileOffset++;
2360 |                             searchOffset++;
2361 |                         }
2362 | 
2363 |                         if (allMatch) {
2364 |                             matchStart = i;
2365 |                             matchEnd = i + fileOffset;
2366 |                             break;
2367 |                         }
2368 |                     }
2369 |                 }
2370 | 
2371 |                 if (matchStart !== -1) {
2372 |                     // Replace the range of lines
2373 |                     const replacement = op.replace_with.split('\n');
2374 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2375 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2376 |                 } else {
2377 |                     success = false;
2378 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2379 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2380 |                 }
2381 |             }
2382 |         });
2383 |         return { content: lines.join('\n'), success, logs };
2384 |     }
