2388 |     async function runAutoFixLoop(name, code, errorList) {
2389 |         const status = document.getElementById('ef-status-msg');
2390 |         let currentCode = code;
2391 |         let currentErrors = errorList;
2392 | 
2393 |         // Fix one by one (recursive loop)
2394 |         async function fixNext(index) {
2395 |             if (index >= currentErrors.length) return true; // All initial errors processed
2396 | 
2397 |             const err = currentErrors[index];
2398 |             status.innerText = `🔧 Fixing Error ${index + 1}/${currentErrors.length} (Line ${err.line})...`;
2399 |             status.style.color = "#eab308"; // Dev yellow
2400 | 
2401 |             try {
2402 |                 // 1. Get Patch from AI
2403 |                 const res = await fetch(CONFIG.funcUrl, { 
2404 |                     method: 'POST', 
2405 |                     headers: {'Content-Type': 'application/json'},
2406 |                     body: apiBody({ 
2407 |                         action: 'propose_syntax_fix', 
2408 |                         code: currentCode, 
2409 |                         error: err 
2410 |                     })
2411 |                 });
2412 |                 const data = await res.json();
2413 |                 const ops = data.operations;
2414 | 
2415 |                 if (!ops || ops === "[]") throw new Error("AI could not generate a fix.");
2416 | 
2417 |                 // 2. Apply Patch Locally
2418 |                 const patchResult = applyLocalPatch(currentCode, ops);
2419 |                 if (!patchResult.success) throw new Error("Generated patch did not match code.");
2420 | 
2421 |                 currentCode = patchResult.content;
2422 |                 document.getElementById('ef-code').value = currentCode; // Update UI
2423 | 
2424 |                 // 3. Re-Validate
2425 |                 const scanRes = await fetch(CONFIG.funcUrl, { 
2426 |                     method: 'POST', headers: {'Content-Type': 'application/json'},
2427 |                     body: apiBody({ action: 'validate_syntax_deep', code_block: currentCode, file_path: 'index.ts' })
2428 |                 });
2429 |                 const scanData = await scanRes.json();
2430 | 
2431 |                 if (scanData.valid) {
2432 |                     status.innerText = "✅ Syntax Fixed!";
2433 |                     return true;
2434 |                 } else {
2435 |                     // If errors remain, update list and Prompt user
2436 |                     currentErrors = scanData.errors;
2437 |                     if (confirm(`Fix applied, but ${currentErrors.length} errors remain. Continue fixing?`)) {
2438 |                         // Recursively fix the *new* first error (since layout changed)
2439 |                         return await fixNext(0);
2440 |                     } else {
2441 |                         return false;
2442 |                     }
2443 |                 }
2444 | 
2445 |             } catch (e) {
2446 |                 if (confirm(`Auto-Fix Failed: ${e.message}\n\nTry again?`)) {
2447 |                     return await fixNext(index);
2448 |                 } else {
2449 |                     return false;
2450 |                 }
2451 |             }
2452 |         }
2453 | 
2454 |         return await fixNext(0);
2455 |     }
