4222 |         const moveFolder = document.getElementById('rn-move-folder').checked;
4223 |         
4224 |         if (!newPath || newPath === currentRenamePath) return closeRenameModal();
4225 |         if (isPerformingAction) return;
4226 |         isPerformingAction = true;
4227 | 
4228 |         const getDir = (p) => p.substring(0, p.lastIndexOf('/') + 1);
4229 |         const oldDir = getDir(currentRenamePath);
4230 |         const newDir = getDir(newPath);
4231 | 
4232 |         showGlobalToast(moveFolder ? "Analyzing folder structure..." : "Preparing move...");
4233 | 
4234 |         try {
4235 |             let ops = [{ "action": "comment", "text": moveFolder ? `[Bulk Move] ${oldDir} -> ${newDir}` : `[Rename] ${currentRenamePath} -> ${newPath}` }];
4236 |             let filesToProcess = [];
4237 | 
4238 |             if (moveFolder && oldDir) {
4239 |                 // Find all siblings
4240 |                 filesToProcess = window.repoFiles.filter(f => f.path.startsWith(oldDir)).map(f => f.path);
4241 |             } else {
4242 |                 filesToProcess = [currentRenamePath];
4243 |             }
4244 | 
4245 |             // Concurrent Content Fetching
4246 |             const BATCH_SIZE = 5;
