4249 |                 const batchResults = await Promise.all(batch.map(async (path) => {
4250 |                     const res = await fetch(CONFIG.funcUrl, {
4251 |                         method: 'POST', headers: {'Content-Type': 'application/json'},
4252 |                         body: apiBody({ action: 'preview_file', file_path: path })
4253 |                     });
