4259 |                     const targetPath = moveFolder ? res.path.replace(oldDir, newDir) : newPath;
4260 |                     ops.push({ "action": "delete_file", "file_path": res.path });
4261 |                     ops.push({ "action": "create_file", "file_path": targetPath, "content": res.content });
4262 |                 });
4263 |             }
4264 | 
4265 |             closeRenameModal();
