5424 |     function formatBytes(bytes) {
5425 |         if (!bytes) return '0 B';
5426 |         const k = 1024;
5427 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5428 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5429 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
5430 |     }
