5432 |     function timeAgo(dateString) {
5433 |         const date = new Date(dateString);
5434 |         const now = new Date();
5435 |         const seconds = Math.floor((now - date) / 1000);
5436 |         if (seconds < 10) return 'just now';
5437 |         if (seconds < 60) return seconds + 's ago';
5438 |         const minutes = Math.floor(seconds / 60);
5439 |         if (minutes < 60) return minutes + 'm ago';
5440 |         const hours = Math.floor(minutes / 60);
5441 |         if (hours < 24) return hours + 'h ago';
5442 |         return date.toLocaleDateString();
5443 |     }
