5695 |                 }
5696 | 
5697 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5698 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5699 | 
