5711 |             }
5712 | 
5713 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5714 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5715 |                 retryCount++;
5716 |                 showGlobalToast("🔍 Searching deeper...");
5717 |                 
5718 |                 await loadMoreFn(); 
5719 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5720 |                 return attemptNavigation();
5721 |             }
5722 | 
5723 |             console.error("[DeepJump] Failed: Element not found after retries.");
5724 |             showGlobalToast("Entry not found in recent history.", true);
5725 |             console.groupEnd();
5726 |             return false;
5727 |         };
