7309 |                     });
7310 |                     const d = await res.json();
7311 |                     return d.content ? b64DecodeUnicode(d.content) : '';
7312 |                 };
7313 | 
7314 |                 const results = await Promise.all([
7315 |                     fetchFile(leftRef).catch(() => ""),
7316 |                     fetchFile(rightRef).catch(() => "")
7317 |                 ]);
