7339 |                 const fullText = session.getValue();
7340 |                 // 1. Try Exact Match
7341 |                 let startIdx = fullText.indexOf(searchText);
7342 |                 
7343 |                 // 2. Try Robust Match (Ignoring Line Endings differences)
