8474 |     function extractTableNames(sql) {
8475 |         if (!sql) return [];
8476 |         const tables = [];
8477 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
8478 |         
8479 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
8480 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
8481 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
8482 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
8483 | 
8484 |         let match;
8485 |         while ((match = fromRegex.exec(sql)) !== null) {
8486 |             const name = match[1];
8487 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
8488 |                 tables.push(name);
8489 |             }
8490 |         }
8491 |         
8492 |         while ((match = metaRegex.exec(sql)) !== null) {
8493 |             const name = match[1];
8494 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
8495 |                 tables.push(name);
8496 |             }
8497 |         }
8498 | 
8499 |         return tables;
8500 |     }
